import { useSelector, useDispatch } from "react-redux";
import { selectTaskCounts } from "../../store/tasksSlice";
import { selectStatusFilter, setStatusFilter, StatusFilter } from "../../store/filtersSlice";
import styles from "./Header.module.css";

const FILTERS = [
  { label: "All", value: StatusFilter.All },
  { label: "Active", value: StatusFilter.Active },
  { label: "Completed", value: StatusFilter.Completed },
];

export default function Header() {
  const dispatch = useDispatch();
  const { completed, active } = useSelector(selectTaskCounts);
  const currentFilter = useSelector(selectStatusFilter);

  return (
    <header className={styles.header}>
      <div className={styles.counts}>
        <span className={styles.countBadge}>
          Completed: <strong>{completed}</strong>
        </span>
        <span className={styles.countBadge}>
          Active: <strong>{active}</strong>
        </span>
      </div>

      <nav className={styles.filters}>
        {FILTERS.map(({ label, value }) => (
          <button
            key={value}
            onClick={() => dispatch(setStatusFilter(value))}
            className={`${styles.filterBtn} ${currentFilter === value ? styles.active : ""}`}
          >
            {label}
          </button>
        ))}
      </nav>
    </header>
  );
}
